/**
 * Utility for wrapping async operations in screen components with
 * automatic loading/error/clear status management.
 *
 * Usage:
 *   return safeExec(this, this.log, async () => {
 *       const events = await AgendaService.fetchEvents();
 *       this.agendaList.events = events;
 *   });
 */

import type { ScreenComponent } from '../types/screen-component.js';
import type { ComponentLogger } from './component-logger.js';

export interface SafeExecOptions {
    /** Skip calling setLoading() — useful for background refreshes. */
    silent?: boolean;
    /** Optional context message to prepend to the error in UI and logs. */
    errorMessage?: string;
}

export async function safeExec(
    screen: ScreenComponent,
    log: ComponentLogger,
    fn: () => Promise<void>,
    options?: SafeExecOptions,
): Promise<void> {
    if (!options?.silent) screen.setLoading();
    try {
        await fn();
        screen.clearStatus();
    } catch (err) {
        const message = options?.errorMessage ?? 'Operation failed';
        log.error(message, err);
        
        if (options?.errorMessage) {
            const displayError = err instanceof Error 
                ? new Error(`${options.errorMessage}: ${err.message}`)
                : new Error(`${options.errorMessage}: ${err}`);
            // Preserve stack and prepend our new message
            if (err instanceof Error && err.stack) {
                displayError.stack = `${displayError.name}: ${displayError.message}\n${err.stack}`;
            }
            screen.setError(displayError);
        } else {
            screen.setError(err);
        }
    }
}
